type Fruit = 'apple' | 'banana' | 'orange';

function getFruitColor(fruit: Fruit): string {
  switch (fruit) {
    case 'apple':
      return 'red';
    case 'banana':
      return 'yellow';
    case 'orange':
      return 'orange';
    default:
      // Using never to catch unexpected cases
      const _exhaustiveCheck: never = fruit;
      return _exhaustiveCheck;
  }
}

from flask import Flask, request, jsonify

app = Flask(__name__)

# In-memory user storage
users = {}

@app.route('/users', methods=['POST'])
def add_user():
    data = request.json
    user_id = str(len(users) + 1)
    users[user_id] = data
    return jsonify({'id': user_id, 'user': data}), 201

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    user = users.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'id': user_id, 'user': user})

if __name__ == '__main__':
    app.run(port=5000, debug=True)

from flask import Flask, request, jsonify
import requests

app = Flask(__name__)

# In-memory order storage
orders = {}

USER_SERVICE_URL = 'http://localhost:5000'

@app.route('/orders', methods=['POST'])
def create_order():
    data = request.json
    user_id = data.get('user_id')
    # Verify user exists by calling User Service
    response = requests.get(f'{USER_SERVICE_URL}/users/{user_id}')
    if response.status_code != 200:
        return jsonify({'error': 'User does not exist'}), 400

    order_id = str(len(orders) + 1)
    orders[order_id] = data
    return jsonify({'id': order_id, 'order': data}), 201

@app.route('/orders/<order_id>', methods=['GET'])
def get_order(order_id):
    order = orders.get(order_id)
    if not order:
        return jsonify({'error': 'Order not found'}), 404
    return jsonify({'id': order_id, 'order': order})

if __name__ == '__main__':
    app.run(port=5001, debug=True)

